int maxSumSubarray(const vector<int>& nums, int k) {
    int window = 0;
    for (int i = 0; i < k; i++) window += nums[i];
    int best = window;
    for (int i = k; i < (int)nums.size(); i++) {
        window += nums[i] - nums[i - k];
        best = max(best, window);
    }
    return best;
}

int main() {
    cout << maxSumSubarray({2, 1, 5, 1, 3, 2}, 3) << endl;  // 9
}

