pair<int,int> twoSumSorted(const vector<int>& nums, int target) {
    int left = 0, right = nums.size() - 1;
    while (left < right) {
        int s = nums[left] + nums[right];
        if (s == target) return {left, right};
        else if (s < target) left++;
        else right--;
    }
    return {-1, -1};
}

int main() {
    auto [i, j] = twoSumSorted({1, 3, 5, 7, 10}, 8);
    cout << i << " " << j << endl;  // 0 4
}

